// lib/security/sanitize.ts
import DOMPurify from 'isomorphic-dompurify'

export function sanitizeHtml(dirty: string): string {
  return DOMPurify.sanitize(dirty, {
    ALLOWED_TAGS: [
      'p', 'br', 'strong', 'em', 'u', 'a', 'ul', 'ol', 'li',
      'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'blockquote', 'code', 'pre'
    ],
    ALLOWED_ATTR: ['href', 'target', 'rel'],
    ALLOW_DATA_ATTR: false,
  })
}

export function sanitizeText(dirty: string): string {
  // Strip ALL HTML tags for plain text fields
  return DOMPurify.sanitize(dirty, {
    ALLOWED_TAGS: [],
    ALLOWED_ATTR: [],
  })
}

export function sanitizeFormData<T extends Record<string, any>>(
  data: T,
  fieldsConfig: Record<keyof T, 'html' | 'text'>
): T {
  const sanitized = {} as T

  for (const [key, value] of Object.entries(data)) {
    const config = fieldsConfig[key as keyof T]

    if (typeof value === 'string') {
      sanitized[key as keyof T] = (
        config === 'html' ? sanitizeHtml(value) : sanitizeText(value)
      ) as T[keyof T]
    } else if (Array.isArray(value)) {
      sanitized[key as keyof T] = value.map(item =>
        typeof item === 'string' && config === 'html'
          ? sanitizeHtml(item)
          : sanitizeText(String(item))
      ) as T[keyof T]
    } else {
      sanitized[key as keyof T] = value
    }
  }

  return sanitized
}

