// lib/env.ts
import { z } from 'zod'

const envSchema = z.object({
  // Required secrets
  CSRF_SECRET: z.string().min(32),
  DATABASE_URL: z.string().url(),
  REDIS_URL: z.string().url(),

  // API keys
  STRAPI_API_TOKEN: z.string().min(1),

  // Feature flags
  ENABLE_RATE_LIMITING: z.enum(['true', 'false']).default('true'),

  // Node environment
  NODE_ENV: z.enum(['development', 'production', 'test']),
})

function validateEnv() {
  const result = envSchema.safeParse(process.env)

  if (!result.success) {
    console.error('❌ Environment validation failed:')
    console.error(result.error.flatten().fieldErrors)
    throw new Error('Invalid environment configuration')
  }

  return result.data
}

export const env = validateEnv()

// lib/startup.ts
import { env } from './env'
import { Redis } from '@upstash/redis'
import { PrismaClient } from '@prisma/client'

export async function validateStartup() {
  const checks = [
    { name: 'Environment', fn: () => env },
    { name: 'Database', fn: async () => {
      const prisma = new PrismaClient()
      await prisma.$connect()
      await prisma.$disconnect()
    }},
    { name: 'Redis', fn: async () => {
      const redis = new Redis({ url: env.REDIS_URL })
      await redis.ping()
    }},
  ]

  for (const check of checks) {
    try {
      await check.fn()
      console.log(`✅ ${check.name} OK`)
    } catch (error) {
      console.error(`❌ ${check.name} FAILED:`, error)
      throw error
    }
  }
}

